    }
    if (n == 1) {
        return 0;
    }
    if (n == 2) {
        return 2;
    }
    if (n == 3) {
        return 0;
    }

    int a = 0;
    int b = 0;
    int c = 2;
    int d = 0;
    int next;
    int i;

    /*@ Inv Assert
            exists next_v,
            next == next_v &&
            n == n@pre &&
            0 <= n@pre && n@pre < 100 &&
            problem_46_pre(n@pre) &&
            fib4_step_int_range(n@pre) &&
            4 <= i && i <= n@pre + 1 &&
            a == fib4(i - 4) &&
            b == fib4(i - 3) &&
            c == fib4(i - 2) &&
            d == fib4(i - 1)
    */
